    session_token_save: 'Salvați acest token pentru a relua sesiunea mai târziu.',
    session_continue: 'Continuă',
    role_select_title: 'Selectați profilul dvs.',
    role_select_subtitle: 'Alegeți opțiunea care descrie cel mai bine rolul dvs.',
    auth_title: 'Verificare email',
